local modules = {}
local cache = {}

local function custom_require(name)
    if cache[name] then
        return cache[name]
    end
    local func = modules[name]
    if not func then
        error("Module not found: " .. tostring(name))
    end
    local result = func()
    cache[name] = result
    return result
end

