	end

	
	local colorPickerFrame = Instance.new("Frame")
	colorPickerFrame.Name = ("ColorPicker_" .. tostring(text))
	colorPickerFrame.Size = UDim2.new(1, 0, 0, 200)
	colorPickerFrame.BackgroundTransparency = 1
	colorPickerFrame.ZIndex = 2

	
