	textLabel.TextXAlignment = Enum.TextXAlignment.Left
	textLabel.TextYAlignment = Enum.TextYAlignment.Center
	textLabel.ZIndex = 2

	textLabel.Parent = colorPickerFrame

	
	local previewButton = Instance.new("TextButton")
	previewButton.Name = "Preview"
	previewButton.Size = UDim2.new(0, 40, 0, 40)
	previewButton.Position = UDim2.new(1, -40, 0, 0)
	previewButton.BackgroundColor3 = default
	previewButton.ZIndex = 2
	previewButton.ClipsDescendants = true

	local previewCorner = Utils.CreateCorner(8, previewButton)
	local previewStroke = Utils.CreateStroke(previewButton, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

	previewButton.Parent = colorPickerFrame

	
	local panel = Instance.new("Frame")
	panel.Name = "Panel"
	panel.Size = UDim2.new(1, 0, 0, 0)
	panel.Position = UDim2.new(0, 0, 0, 44)
	panel.BackgroundColor3 = Theme.Colors.BackgroundTertiary
	panel.BackgroundTransparency = Theme.Transparency.BackgroundTertiary
	panel.ZIndex = 2
	panel.ClipsDescendants = true

	local panelCorner = Utils.CreateCorner(Theme.CornerRadius.WidgetOuter, panel)
	local panelStroke = Utils.CreateStroke(panel, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

	panel.Parent = colorPickerFrame

	
	local svArea = Instance.new("Frame")
	svArea.Name = "SVArea"
	svArea.Size = UDim2.new(1, -16, 0, 120)
	svArea.Position = UDim2.new(0, 8, 0, 8)
	svArea.BackgroundColor3 = Color3.fromHex("#ff0000")
	svArea.ZIndex = 3
	svArea.ClipsDescendants = true

	local svCorner = Utils.CreateCorner(Theme.CornerRadius.Small, svArea)

	
	local whiteOverlay = Instance.new("Frame")
	whiteOverlay.Name = "WhiteOverlay"
	whiteOverlay.Size = UDim2.new(1, 0, 1, 0)
	whiteOverlay.Position = UDim2.new(0, 0, 0, 0)
	whiteOverlay.BackgroundColor3 = Color3.fromHex("#ffffff")
	whiteOverlay.ZIndex = 4

	whiteOverlay.Parent = svArea

	
	local blackOverlay = Instance.new("Frame")
	blackOverlay.Name = "BlackOverlay"
	blackOverlay.Size = UDim2.new(1, 0, 1, 0)
	blackOverlay.Position = UDim2.new(0, 0, 0, 0)
	blackOverlay.BackgroundTransparency = 0.5
	blackOverlay.ZIndex = 5

	blackOverlay.Parent = svArea

	svArea.Parent = panel

	
	local svSelector = Instance.new("Frame")
	svSelector.Name = "Selector"
	svSelector.Size = UDim2.new(0, 16, 0, 16)
	svSelector.Position = UDim2.new(0.5, -8, 0.5, -8)
	svSelector.BackgroundTransparency = 1
	svSelector.ZIndex = 6

	local selectorCorner = Utils.CreateCorner(8, svSelector)
	local selectorStroke = Utils.CreateStroke(svSelector, Color3.new(1, 1, 1), 2, 0)

	svSelector.Parent = svArea

	
	local hueSlider = Instance.new("Frame")
	hueSlider.Name = "HueSlider"
	hueSlider.Size = UDim2.new(1, -16, 0, 20)
	hueSlider.Position = UDim2.new(0, 8, 0, 136)
	hueSlider.BackgroundColor3 = Color3.fromHex("#ff0000")
	hueSlider.ZIndex = 3
	hueSlider.ClipsDescendants = true

	local hueCorner = Utils.CreateCorner(4, hueSlider)

	
	local hueGradient = Instance.new("Frame")
	hueGradient.Name = "Gradient"
	hueGradient.Size = UDim2.new(1, 0, 1, 0)
	hueGradient.Position = UDim2.new(0, 0, 0, 0)
	hueGradient.BackgroundTransparency = 1
	hueGradient.ZIndex = 4

	
	local hueImage = Instance.new("ImageLabel")
	hueImage.Name = "HueImage"
	hueImage.Size = UDim2.new(1, 0, 1, 0)
	hueImage.Position = UDim2.new(0, 0, 0, 0)
	hueImage.BackgroundTransparency = 1
	hueImage.Image = "rbxassetid://6434342429" 
	hueImage.ZIndex = 4

	hueImage.Parent = hueGradient
	hueGradient.Parent = hueSlider

	
	local hueThumb = Instance.new("Frame")
	hueThumb.Name = "Thumb"
	hueThumb.Size = UDim2.new(0, 4, 0, 24)
	hueThumb.Position = UDim2.new(0.5, -2, 0.5, -12)
	hueThumb.BackgroundColor3 = Color3.new(1, 1, 1)
	hueThumb.ZIndex = 5
	hueThumb.ClipsDescendants = true

	local hueThumbCorner = Utils.CreateCorner(2, hueThumb)
	local hueThumbStroke = Utils.CreateStroke(hueThumb, Color3.new(0, 0, 0), 1, 0)

	hueThumb.Parent = hueSlider

	hueSlider.Parent = panel

	
	local colorPickerState = {
		Frame = colorPickerFrame,
		Panel = panel,
		PreviewButton = previewButton,
		SVArea = svArea,
		SVSelector = svSelector,
		HueSlider = hueSlider,
		HueThumb = hueThumb,
		CurrentColor = default,
		Hue = 0,
		Saturation = 1,
		Value = 1,
		IsOpen = false,
		Callback = callback,
	}

	
	local function hsvToColor(h, s, v)
		local c = v * s
		local x = c * (1 - math.abs((h / 60) % 2 - 1))
		local m = v - c

		local r, g, b = 0, 0, 0

		if h < 60 then
			r, g, b = c, x, 0
		elseif h < 120 then
			r, g, b = x, c, 0
		elseif h < 180 then
			r, g, b = 0, c, x
		elseif h < 240 then
			r, g, b = 0, x, c
		elseif h < 300 then
			r, g, b = x, 0, c
		else
			r, g, b = c, 0, x
		end

		return Color3.new(r + m, g + m, b + m)
	end

	
	local function updateColor()
		local color = hsvToColor(colorPickerState.Hue, colorPickerState.Saturation, colorPickerState.Value)
		colorPickerState.CurrentColor = color

		
		previewButton.BackgroundColor3 = color

		
		local baseColor = hsvToColor(colorPickerState.Hue, 1, 1)
		svArea.BackgroundColor3 = baseColor

		
		svSelector.Position = UDim2.new(colorPickerState.Saturation, -8, 1 - colorPickerState.Value, -8)

		
		task.spawn(callback, color)
	end

	
	previewButton.MouseButton1Click:Connect(function()
		colorPickerState.IsOpen = not colorPickerState.IsOpen

		if colorPickerState.IsOpen then
			
			panel.Visible = true
			panel.Size = UDim2.new(1, 0, 0, 0)

			Utils.Tween(panel, {
				Size = UDim2.new(1, 0, 0, 160),
			}, 0.25, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		else
			
			Utils.Tween(panel, {
				Size = UDim2.new(1, 0, 0, 0),
			}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

			task.delay(0.2, function()
				panel.Visible = false
			end)
		end
	end)

	
	local function svDrag(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			local connection = RunService.Heartbeat:Connect(function()
				local mousePos = UserInputService:GetMouseLocation()
				local areaPos = svArea.AbsolutePosition
				local areaSize = svArea.AbsoluteSize

				local relativeX = math.clamp(mousePos.X - areaPos.X, 0, areaSize.X)
				local relativeY = math.clamp(mousePos.Y - areaPos.Y, 0, areaSize.Y)

				colorPickerState.Saturation = relativeX / areaSize.X
				colorPickerState.Value = 1 - (relativeY / areaSize.Y)

				updateColor()
			end)

			input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					connection:Disconnect()
				end
			end)
		end
	end

	svArea.InputBegan:Connect(svDrag)
	svSelector.InputBegan:Connect(svDrag)

	
	local function hueDrag(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			local connection = RunService.Heartbeat:Connect(function()
				local mousePos = UserInputService:GetMouseLocation()
				local sliderPos = hueSlider.AbsolutePosition.X
				local sliderWidth = hueSlider.AbsoluteSize.X

				local relativeX = math.clamp(mousePos.X - sliderPos, 0, sliderWidth)
				local percent = relativeX / sliderWidth

				colorPickerState.Hue = percent * 360
				hueThumb.Position = UDim2.new(percent, -2, 0.5, -12)

				updateColor()
			end)

			input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					connection:Disconnect()
				end
			end)
		end
	end

	hueSlider.InputBegan:Connect(hueDrag)
	hueThumb.InputBegan:Connect(hueDrag)

	
	updateColor()

	
	function colorPickerState:SetColor(color: Color3)
		colorPickerState.CurrentColor = color
		previewButton.BackgroundColor3 = color

		
		local h, s, v = Color3.toHSV(color)
		colorPickerState.Hue = h * 360
		colorPickerState.Saturation = s
		colorPickerState.Value = v

		updateColor()
	end

	function colorPickerState:GetColor(): Color3
		return colorPickerState.CurrentColor
	end

	function colorPickerState:SetCallback(newCallback: (Color3) -> ())
		colorPickerState.Callback = newCallback
	end

	function colorPickerState:Destroy()
		Utils.Tween(colorPickerFrame, {
			Transparency = 1,
			Size = UDim2.new(0.5, 0, 0, 0),
			Position = UDim2.new(0.25, 0, 0.5, 0),
		}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

		task.delay(0.2, function()
			colorPickerFrame:Destroy()
		end)
	end

	
	colorPickerFrame.Parent = parent

	return colorPickerState
end

return ColorPicker
end

modules["components/inputs/dropdown"] = function()



local Dropdown = {}
Dropdown.__index = Dropdown

local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")
local Icons = custom_require("core/icons")


function Dropdown.Create(config: table)
	config = config or {}
	local parent = config.Parent
	local text = config.Text or "Dropdown"
	local options = config.Options or {}
	local default = config.Default or ""
	local callback = config.Callback or function() end

	if not parent then
		error("Dropdown requires a parent frame")
	end

	
	local dropdownFrame = Instance.new("Frame")
	dropdownFrame.Name = ("Dropdown_" .. tostring(text))
	dropdownFrame.Size = UDim2.new(1, 0, 0, 40)
	dropdownFrame.BackgroundTransparency = 1
	dropdownFrame.ZIndex = 2

	
	local textLabel = Instance.new("TextLabel")
	textLabel.Name = "Text"
	textLabel.Size = UDim2.new(0, 150, 0, 20)
	textLabel.Position = UDim2.new(0, 0, 0, 0)
	textLabel.BackgroundTransparency = 1
	textLabel.Text = text
	textLabel.TextColor3 = Theme.Colors.TextPrimary
	textLabel.TextSize = Theme.Font.Size.Body
	textLabel.Font = Theme.Font.Family
	textLabel.TextXAlignment = Enum.TextXAlignment.Left
	textLabel.TextYAlignment = Enum.TextYAlignment.Center
	textLabel.ZIndex = 2

	textLabel.Parent = dropdownFrame

	
	local dropdownButton = Instance.new("TextButton")
	dropdownButton.Name = "Button"
	dropdownButton.Size = UDim2.new(1, 0, 0, 32)
	dropdownButton.Position = UDim2.new(0, 0, 1, -32)
	dropdownButton.BackgroundColor3 = Theme.Colors.BackgroundTertiary
	dropdownButton.BackgroundTransparency = Theme.Transparency.BackgroundTertiary
	dropdownButton.ZIndex = 2
	dropdownButton.ClipsDescendants = true

	local buttonCorner = Utils.CreateCorner(Theme.CornerRadius.WidgetOuter, dropdownButton)
	local buttonStroke = Utils.CreateStroke(dropdownButton, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

	dropdownButton.Parent = dropdownFrame

	
	local selectedText = Instance.new("TextLabel")
	selectedText.Name = "Selected"
	selectedText.Size = UDim2.new(1, -40, 1, 0)
	selectedText.Position = UDim2.new(0, 12, 0, 0)
	selectedText.BackgroundTransparency = 1
	selectedText.Text = default ~= "" and default or "Select..."
	selectedText.TextColor3 = default ~= "" and Theme.Colors.TextPrimary or Theme.Colors.TextMuted
	selectedText.TextSize = Theme.Font.Size.Body
	selectedText.Font = Theme.Font.Family
	selectedText.TextXAlignment = Enum.TextXAlignment.Left
	selectedText.TextYAlignment = Enum.TextYAlignment.Center
	selectedText.ZIndex = 3

	selectedText.Parent = dropdownButton

	
	local arrowIcon = Icons.Create(
		"caret-down",
		dropdownButton,
		UDim2.new(0, 20, 0, 20),
		UDim2.new(1, -28, 0.5, -10),
		Theme.Colors.TextSecondary,
		0.8
	)

	
	local dropdownList = Instance.new("ScrollingFrame")
	dropdownList.Name = "List"
	dropdownList.Size = UDim2.new(1, 0, 0, 0)
	dropdownList.Position = UDim2.new(0, 0, 1, 0)
	dropdownList.BackgroundColor3 = Theme.Colors.BackgroundSecondary
	dropdownList.BackgroundTransparency = Theme.Transparency.BackgroundSecondary
	dropdownList.ZIndex = 10
	dropdownList.Visible = false
	dropdownList.ClipsDescendants = true
	dropdownList.ScrollBarThickness = 4
	dropdownList.ScrollBarImageColor3 = Theme.Colors.AccentPrimary
	dropdownList.CanvasSize = UDim2.new(0, 0, 0, 0)
	Utils.AutoCanvasY(dropdownList)

	local listCorner = Utils.CreateCorner(Theme.CornerRadius.WidgetOuter, dropdownList)
	local listStroke = Utils.CreateStroke(dropdownList, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

	dropdownList.Parent = dropdownFrame

	
	local listLayout = Instance.new("UIListLayout")
	listLayout.FillDirection = Enum.FillDirection.Vertical
	listLayout.HorizontalAlignment = Enum.HorizontalAlignment.Center
	listLayout.VerticalAlignment = Enum.VerticalAlignment.Top
	listLayout.Padding = UDim.new(0, 4)
	listLayout.SortOrder = Enum.SortOrder.LayoutOrder
	listLayout.Parent = dropdownList

	
	local dropdownState = {
		Frame = dropdownFrame,
		Button = dropdownButton,
		SelectedText = selectedText,
		List = dropdownList,
		ListLayout = listLayout,
		Options = options,
		SelectedValue = default,
		IsOpen = false,
		Callback = callback,
		OptionButtons = {},
	}

	
	local function toggleDropdown()
		dropdownState.IsOpen = not dropdownState.IsOpen

		if dropdownState.IsOpen then
			
			dropdownList.Visible = true
			dropdownList.Size = UDim2.new(1, 0, 0, 0)

			
			for i, option in ipairs(options) do
				local optionButton = Instance.new("TextButton")
				optionButton.Name = ("Option_" .. tostring(option))
				optionButton.Size = UDim2.new(1, 0, 0, 28)
				optionButton.BackgroundTransparency = 1
				optionButton.Text = option
				optionButton.TextColor3 = Theme.Colors.TextPrimary
				optionButton.TextSize = Theme.Font.Size.Body
				optionButton.Font = Theme.Font.Family
				optionButton.TextXAlignment = Enum.TextXAlignment.Left
				optionButton.ZIndex = 11

				optionButton.Parent = dropdownList
				table.insert(dropdownState.OptionButtons, optionButton)

				
				optionButton.InputBegan:Connect(function(input)
					if input.UserInputType == Enum.UserInputType.MouseMovement then
						Utils.Tween(optionButton, {
							BackgroundColor3 = Theme.Colors.BackgroundHover,
							BackgroundTransparency = Theme.Transparency.BackgroundHover,
						}, 0.1, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
					end
				end)

				optionButton.InputEnded:Connect(function(input)
					if input.UserInputType == Enum.UserInputType.MouseMovement then
						Utils.Tween(optionButton, {
							BackgroundColor3 = Theme.Colors.BackgroundSecondary,
							BackgroundTransparency = Theme.Transparency.BackgroundSecondary,
						}, 0.1, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
					end
				end)

				
				optionButton.MouseButton1Click:Connect(function()
					dropdownState.SelectedValue = option
					selectedText.Text = option
					selectedText.TextColor3 = Theme.Colors.TextPrimary

					
					toggleDropdown()

					
					task.spawn(callback, option)
				end)
			end

			
			task.wait(0.01)
			dropdownList.Size = UDim2.new(1, 0, 0, math.clamp(#options * 32, 0, 200))

			
			Utils.Tween(arrowIcon, {
				Rotation = 180,
			}, 0.25, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		else
			
			Utils.Tween(dropdownList, {
				Size = UDim2.new(1, 0, 0, 0),
				Transparency = 1,
			}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

			
			Utils.Tween(arrowIcon, {
				Rotation = 0,
			}, 0.25, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

			task.delay(0.2, function()
				dropdownList.Visible = false
				dropdownList.Transparency = 0

				
				for _, btn in pairs(dropdownState.OptionButtons) do
					if btn.Parent then
						btn:Destroy()
					end
				end
				table.clear(dropdownState.OptionButtons)
			end)
		end
	end

	
	dropdownButton.MouseButton1Click:Connect(toggleDropdown)

	
	dropdownButton.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 then
			
			Utils.Tween(dropdownButton, {
				BackgroundTransparency = 0.5,
			}, 0.1, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		end
	end)

	dropdownButton.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 then
			Utils.Tween(dropdownButton, {
				BackgroundTransparency = Theme.Transparency.BackgroundTertiary,
			}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		end
	end)

	
	function dropdownState:SetOptions(newOptions: {string})
		dropdownState.Options = newOptions
	end

	function dropdownState:SetValue(value: string)
		dropdownState.SelectedValue = value
		selectedText.Text = value
		selectedText.TextColor3 = Theme.Colors.TextPrimary
	end

	function dropdownState:GetValue(): string
		return dropdownState.SelectedValue
	end

	function dropdownState:SetCallback(newCallback: (string) -> ())
		dropdownState.Callback = newCallback
	end

	function dropdownState:Open()
		if not dropdownState.IsOpen then
			toggleDropdown()
		end
	end

	function dropdownState:Close()
		if dropdownState.IsOpen then
			toggleDropdown()
		end
	end

	function dropdownState:Destroy()
		if dropdownState.IsOpen then
			toggleDropdown()
		end

		Utils.Tween(dropdownFrame, {
			Transparency = 1,
			Size = UDim2.new(0.5, 0, 0, 0),
			Position = UDim2.new(0.25, 0, 0.5, 0),
		}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

		task.delay(0.2, function()
			dropdownFrame:Destroy()
		end)
	end

	
	dropdownFrame.Parent = parent

	return dropdownState
end

return Dropdown
end

