	textLabel.Font = Theme.Font.Family
	textLabel.TextXAlignment = Enum.TextXAlignment.Left
	textLabel.TextYAlignment = Enum.TextYAlignment.Center
	textLabel.ZIndex = 2

	textLabel.Parent = keybindFrame

	
	local keybindButton = Instance.new("TextButton")
	keybindButton.Name = "Button"
	keybindButton.Size = UDim2.new(0, 120, 0, 32)
	keybindButton.Position = UDim2.new(1, -120, 0.5, -16)
	keybindButton.BackgroundColor3 = Theme.Colors.BackgroundTertiary
	keybindButton.BackgroundTransparency = Theme.Transparency.BackgroundTertiary
	keybindButton.Text = default ~= Enum.KeyCode.Unknown and default.Name or "Press Key"
	keybindButton.TextColor3 = default ~= Enum.KeyCode.Unknown and Theme.Colors.TextPrimary or Theme.Colors.TextMuted
	keybindButton.TextSize = Theme.Font.Size.Body
	keybindButton.Font = Theme.Font.Family
	keybindButton.ZIndex = 2
	keybindButton.ClipsDescendants = true

	local buttonCorner = Utils.CreateCorner(Theme.CornerRadius.WidgetOuter, keybindButton)
	local buttonStroke = Utils.CreateStroke(keybindButton, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

	keybindButton.Parent = keybindFrame

	
	local keybindState = {
		Frame = keybindFrame,
		Button = keybindButton,
		CurrentKey = default,
		IsListening = false,
		Callback = callback,
		Mode = mode,
		IsActive = false,
	}

	
	local function startListening()
		keybindState.IsListening = true
		keybindButton.Text = "Press Key..."
		keybindButton.TextColor3 = Theme.Colors.AccentSecondary

		Utils.Tween(keybindButton, {
			BackgroundColor3 = Theme.Colors.AccentPrimary,
			BackgroundTransparency = 0.3,
		}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
	end

	
	local function stopListening()
		keybindState.IsListening = false
		keybindButton.Text = keybindState.CurrentKey ~= Enum.KeyCode.Unknown and keybindState.CurrentKey.Name or "Press Key"
		keybindButton.TextColor3 = keybindState.CurrentKey ~= Enum.KeyCode.Unknown and Theme.Colors.TextPrimary or Theme.Colors.TextMuted

		Utils.Tween(keybindButton, {
			BackgroundColor3 = Theme.Colors.BackgroundTertiary,
			BackgroundTransparency = Theme.Transparency.BackgroundTertiary,
		}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
	end

	
	keybindButton.MouseButton1Click:Connect(function()
		if not keybindState.IsListening then
			startListening()
		else
			stopListening()
		end
	end)

	
	local inputConnection = UserInputService.InputBegan:Connect(function(input, gameProcessed)
		if keybindState.IsListening and input.KeyCode ~= Enum.KeyCode.Unknown then
			keybindState.CurrentKey = input.KeyCode
			stopListening()
			task.spawn(callback, input.KeyCode)
		elseif not keybindState.IsListening and keybindState.CurrentKey ~= Enum.KeyCode.Unknown then
			if input.KeyCode == keybindState.CurrentKey and not gameProcessed then
				if keybindState.Mode == "Toggle" then
					keybindState.IsActive = not keybindState.IsActive
					task.spawn(callback, keybindState.CurrentKey, keybindState.IsActive)
				elseif keybindState.Mode == "Hold" then
					keybindState.IsActive = true
					task.spawn(callback, keybindState.CurrentKey, true)
				end
			end
		end
	end)

	local inputEndedConnection = UserInputService.InputEnded:Connect(function(input)
		if not keybindState.IsListening and keybindState.CurrentKey ~= Enum.KeyCode.Unknown then
			if input.KeyCode == keybindState.CurrentKey and keybindState.Mode == "Hold" then
				keybindState.IsActive = false
				task.spawn(callback, keybindState.CurrentKey, false)
			end
		end
	end)

	
	keybindButton.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement and not keybindState.IsListening then
			Utils.Tween(keybindButton, {
				BackgroundColor3 = Theme.Colors.BackgroundHover,
				BackgroundTransparency = Theme.Transparency.BackgroundHover,
			}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		end
	end)

	keybindButton.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement and not keybindState.IsListening then
			Utils.Tween(keybindButton, {
				BackgroundColor3 = Theme.Colors.BackgroundTertiary,
				BackgroundTransparency = Theme.Transparency.BackgroundTertiary,
			}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		end
	end)

	
	function keybindState:SetKey(keyCode: Enum.KeyCode)
		keybindState.CurrentKey = keyCode
		keybindButton.Text = keyCode.Name
		keybindButton.TextColor3 = Theme.Colors.TextPrimary
	end

	function keybindState:GetKey(): Enum.KeyCode
		return keybindState.CurrentKey
	end

	function keybindState:SetCallback(newCallback: (Enum.KeyCode, boolean?) -> ())
		keybindState.Callback = newCallback
	end

	function keybindState:SetMode(newMode: string)
		keybindState.Mode = newMode
	end

	function keybindState:IsPressed(): boolean
		return keybindState.IsActive
	end

	function keybindState:Destroy()
		inputConnection:Disconnect()
		inputEndedConnection:Disconnect()

		Utils.Tween(keybindFrame, {
			Transparency = 1,
			Size = UDim2.new(0.5, 0, 0, 0),
			Position = UDim2.new(0.25, 0, 0.5, 0),
		}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

		task.delay(0.2, function()
			keybindFrame:Destroy()
		end)
	end

	
	keybindFrame.Parent = parent

	return keybindState
end

return Keybind
end

modules["components/inputs/multidropdown"] = function()



local MultiDropdown = {}
MultiDropdown.__index = MultiDropdown

local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")
local Icons = custom_require("core/icons")


function MultiDropdown.Create(config: table)
	config = config or {}
	local parent = config.Parent
	local text = config.Text or "MultiDropdown"
	local options = config.Options or {}
	local default = config.Default or {}
	local callback = config.Callback or function() end

	if not parent then
		error("MultiDropdown requires a parent frame")
	end

	
	local multidropdownFrame = Instance.new("Frame")
	multidropdownFrame.Name = ("MultiDropdown_" .. tostring(text))
	multidropdownFrame.Size = UDim2.new(1, 0, 0, 40)
	multidropdownFrame.BackgroundTransparency = 1
	multidropdownFrame.ZIndex = 2

	
	local textLabel = Instance.new("TextLabel")
	textLabel.Name = "Text"
	textLabel.Size = UDim2.new(0, 150, 0, 20)
	textLabel.Position = UDim2.new(0, 0, 0, 0)
	textLabel.BackgroundTransparency = 1
	textLabel.Text = text
	textLabel.TextColor3 = Theme.Colors.TextPrimary
	textLabel.TextSize = Theme.Font.Size.Body
	textLabel.Font = Theme.Font.Family
	textLabel.TextXAlignment = Enum.TextXAlignment.Left
	textLabel.TextYAlignment = Enum.TextYAlignment.Center
	textLabel.ZIndex = 2

	textLabel.Parent = multidropdownFrame

	
	local dropdownButton = Instance.new("TextButton")
	dropdownButton.Name = "Button"
	dropdownButton.Size = UDim2.new(1, 0, 0, 32)
	dropdownButton.Position = UDim2.new(0, 0, 1, -32)
	dropdownButton.BackgroundColor3 = Theme.Colors.BackgroundTertiary
	dropdownButton.BackgroundTransparency = Theme.Transparency.BackgroundTertiary
	dropdownButton.ZIndex = 2
	dropdownButton.ClipsDescendants = true

	local buttonCorner = Utils.CreateCorner(Theme.CornerRadius.WidgetOuter, dropdownButton)
	local buttonStroke = Utils.CreateStroke(dropdownButton, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

	dropdownButton.Parent = multidropdownFrame

	
	local selectedText = Instance.new("TextLabel")
	selectedText.Name = "Selected"
	selectedText.Size = UDim2.new(1, -40, 1, 0)
	selectedText.Position = UDim2.new(0, 12, 0, 0)
	selectedText.BackgroundTransparency = 1
	selectedText.Text = #default > 0 and (tostring(#default) .. " selected") or "Select..."
	selectedText.TextColor3 = #default > 0 and Theme.Colors.TextPrimary or Theme.Colors.TextMuted
	selectedText.TextSize = Theme.Font.Size.Body
	selectedText.Font = Theme.Font.Family
	selectedText.TextXAlignment = Enum.TextXAlignment.Left
	selectedText.TextYAlignment = Enum.TextYAlignment.Center
	selectedText.ZIndex = 3

	selectedText.Parent = dropdownButton

	
	local arrowIcon = Icons.Create(
		"caret-down",
		dropdownButton,
		UDim2.new(0, 20, 0, 20),
		UDim2.new(1, -28, 0.5, -10),
		Theme.Colors.TextSecondary,
		0.8
	)

	
	local dropdownList = Instance.new("ScrollingFrame")
	dropdownList.Name = "List"
	dropdownList.Size = UDim2.new(1, 0, 0, 0)
	dropdownList.Position = UDim2.new(0, 0, 1, 0)
	dropdownList.BackgroundColor3 = Theme.Colors.BackgroundSecondary
	dropdownList.BackgroundTransparency = Theme.Transparency.BackgroundSecondary
	dropdownList.ZIndex = 10
	dropdownList.Visible = false
	dropdownList.ClipsDescendants = true
	dropdownList.ScrollBarThickness = 4
	dropdownList.ScrollBarImageColor3 = Theme.Colors.AccentPrimary
	dropdownList.CanvasSize = UDim2.new(0, 0, 0, 0)
	Utils.AutoCanvasY(dropdownList)

	local listCorner = Utils.CreateCorner(Theme.CornerRadius.WidgetOuter, dropdownList)
	local listStroke = Utils.CreateStroke(dropdownList, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

	dropdownList.Parent = multidropdownFrame

	
	local listLayout = Instance.new("UIListLayout")
	listLayout.FillDirection = Enum.FillDirection.Vertical
	listLayout.HorizontalAlignment = Enum.HorizontalAlignment.Center
	listLayout.VerticalAlignment = Enum.VerticalAlignment.Top
	listLayout.Padding = UDim.new(0, 4)
	listLayout.SortOrder = Enum.SortOrder.LayoutOrder
	listLayout.Parent = dropdownList

	
	local multidropdownState = {
		Frame = multidropdownFrame,
		Button = dropdownButton,
		SelectedText = selectedText,
		List = dropdownList,
		ListLayout = listLayout,
		Options = options,
		SelectedValues = {},
		IsOpen = false,
		Callback = callback,
		OptionButtons = {},
	}

	
	for _, val in ipairs(default) do
		multidropdownState.SelectedValues[val] = true
	end

	
	local function updateSelectedText()
		local count = 0
		for _, _ in pairs(multidropdownState.SelectedValues) do
			count = count + (1)
		end

		if count > 0 then
			selectedText.Text = (tostring(count) .. " selected")
			selectedText.TextColor3 = Theme.Colors.TextPrimary
		else
			selectedText.Text = "Select..."
			selectedText.TextColor3 = Theme.Colors.TextMuted
		end
	end

	
	local function toggleDropdown()
		multidropdownState.IsOpen = not multidropdownState.IsOpen

		if multidropdownState.IsOpen then
			
			dropdownList.Visible = true
			dropdownList.Size = UDim2.new(1, 0, 0, 0)

			
			for _, btn in pairs(multidropdownState.OptionButtons) do
				if btn.Parent then
					btn:Destroy()
				end
			end
			table.clear(multidropdownState.OptionButtons)

			
			for i, option in ipairs(options) do
				local optionButton = Instance.new("TextButton")
				optionButton.Name = ("Option_" .. tostring(option))
				optionButton.Size = UDim2.new(1, 0, 0, 28)
				optionButton.BackgroundTransparency = 1
				optionButton.Text = option
				optionButton.TextColor3 = Theme.Colors.TextPrimary
				optionButton.TextSize = Theme.Font.Size.Body
				optionButton.Font = Theme.Font.Family
				optionButton.TextXAlignment = Enum.TextXAlignment.Left
				optionButton.ZIndex = 11

				
				local checkbox = Instance.new("Frame")
				checkbox.Name = "Checkbox"
				checkbox.Size = UDim2.new(0, 18, 0, 18)
				checkbox.Position = UDim2.new(1, -32, 0.5, -9)
				checkbox.BackgroundColor3 = multidropdownState.SelectedValues[option] and Theme.Colors.AccentPrimary or Theme.Colors.BackgroundTertiary
				checkbox.BackgroundTransparency = multidropdownState.SelectedValues[option] and 0.2 or Theme.Transparency.BackgroundTertiary
				checkbox.ZIndex = 12
				checkbox.ClipsDescendants = true

				local checkboxCorner = Utils.CreateCorner(4, checkbox)

				
				local checkmark = nil
				if multidropdownState.SelectedValues[option] then
					checkmark = Icons.Create(
						"check",
						checkbox,
						UDim2.new(0, 12, 0, 12),
						UDim2.new(0.5, -6, 0.5, -6),
						Theme.Colors.AccentPrimary,
						0
					)
				end

				checkbox.Parent = optionButton

				optionButton.Parent = dropdownList
				table.insert(multidropdownState.OptionButtons, optionButton)

				
				optionButton.InputBegan:Connect(function(input)
					if input.UserInputType == Enum.UserInputType.MouseMovement then
						Utils.Tween(optionButton, {
							BackgroundColor3 = Theme.Colors.BackgroundHover,
							BackgroundTransparency = Theme.Transparency.BackgroundHover,
						}, 0.1, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
					end
				end)

				optionButton.InputEnded:Connect(function(input)
					if input.UserInputType == Enum.UserInputType.MouseMovement then
						Utils.Tween(optionButton, {
							BackgroundColor3 = Theme.Colors.BackgroundSecondary,
							BackgroundTransparency = Theme.Transparency.BackgroundSecondary,
						}, 0.1, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
					end
				end)

				
				optionButton.MouseButton1Click:Connect(function()
					if multidropdownState.SelectedValues[option] then
						multidropdownState.SelectedValues[option] = nil
					else
						multidropdownState.SelectedValues[option] = true
					end

					
					local isSelected = multidropdownState.SelectedValues[option]
					checkbox.BackgroundColor3 = isSelected and Theme.Colors.AccentPrimary or Theme.Colors.BackgroundTertiary
					checkbox.BackgroundTransparency = isSelected and 0.2 or Theme.Transparency.BackgroundTertiary

					if isSelected and not checkmark then
						checkmark = Icons.Create(
							"check",
							checkbox,
							UDim2.new(0, 12, 0, 12),
							UDim2.new(0.5, -6, 0.5, -6),
							Theme.Colors.AccentPrimary,
							0
						)
					elseif not isSelected and checkmark then
						checkmark:Destroy()
						checkmark = nil
					end

					
					updateSelectedText()

					
					local selectedList = {}
					for val, _ in pairs(multidropdownState.SelectedValues) do
						table.insert(selectedList, val)
					end

					
					task.spawn(callback, selectedList)
				end)
			end

			
			task.wait(0.01)
			dropdownList.Size = UDim2.new(1, 0, 0, math.clamp(#options * 32, 0, 200))

			
			Utils.Tween(arrowIcon, {
				Rotation = 180,
			}, 0.25, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		else
			
			Utils.Tween(dropdownList, {
				Size = UDim2.new(1, 0, 0, 0),
				Transparency = 1,
			}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

			
			Utils.Tween(arrowIcon, {
				Rotation = 0,
			}, 0.25, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

			task.delay(0.2, function()
				dropdownList.Visible = false
				dropdownList.Transparency = 0

				
				for _, btn in pairs(multidropdownState.OptionButtons) do
					if btn.Parent then
						btn:Destroy()
					end
				end
				table.clear(multidropdownState.OptionButtons)
			end)
		end
	end

	
	dropdownButton.MouseButton1Click:Connect(toggleDropdown)

	
	function multidropdownState:SetOptions(newOptions: {string})
		multidropdownState.Options = newOptions
	end

	function multidropdownState:SetValue(values: {string})
		multidropdownState.SelectedValues = {}
		for _, val in ipairs(values) do
			multidropdownState.SelectedValues[val] = true
		end
		updateSelectedText()
	end

	function multidropdownState:GetValue(): {string}
		local selectedList = {}
		for val, _ in pairs(multidropdownState.SelectedValues) do
			table.insert(selectedList, val)
		end
		return selectedList
	end

	function multidropdownState:SetCallback(newCallback: ({string}) -> ())
		multidropdownState.Callback = newCallback
	end

	function multidropdownState:Open()
		if not multidropdownState.IsOpen then
			toggleDropdown()
		end
	end

	function multidropdownState:Close()
		if multidropdownState.IsOpen then
			toggleDropdown()
		end
	end

	function multidropdownState:Destroy()
		if multidropdownState.IsOpen then
			toggleDropdown()
		end

		Utils.Tween(multidropdownFrame, {
			Transparency = 1,
			Size = UDim2.new(0.5, 0, 0, 0),
			Position = UDim2.new(0.25, 0, 0.5, 0),
		}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

		task.delay(0.2, function()
			multidropdownFrame:Destroy()
		end)
	end

	
	multidropdownFrame.Parent = parent

	return multidropdownState
end

return MultiDropdown
end

modules["components/inputs/slider"] = function()



local Slider = {}
Slider.__index = Slider

local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")


function Slider.Create(config: table)
	config = config or {}
	local parent = config.Parent
	local text = config.Text or "Slider"
	local min = config.Min or 0
	local max = config.Max or 100
	local default = config.Default or 50
	local step = config.Step or 1
	local callback = config.Callback or function() end

	if not parent then
		error("Slider requires a parent frame")
	end

	
	local sliderFrame = Instance.new("Frame")
	sliderFrame.Name = ("Slider_" .. tostring(text))
	sliderFrame.Size = UDim2.new(1, 0, 0, 44)
	sliderFrame.BackgroundTransparency = 1
	sliderFrame.ZIndex = 2

	
	local textLabel = Instance.new("TextLabel")
	textLabel.Name = "Text"
	textLabel.Size = UDim2.new(0, 150, 0, 20)
	textLabel.Position = UDim2.new(0, 0, 0, 0)
	textLabel.BackgroundTransparency = 1
	textLabel.Text = text
	textLabel.TextColor3 = Theme.Colors.TextPrimary
	textLabel.TextSize = Theme.Font.Size.Body
	textLabel.Font = Theme.Font.Family
	textLabel.TextXAlignment = Enum.TextXAlignment.Left
	textLabel.TextYAlignment = Enum.TextYAlignment.Center
	textLabel.ZIndex = 2

	textLabel.Parent = sliderFrame

	
	local valueLabel = Instance.new("TextLabel")
	valueLabel.Name = "Value"
	valueLabel.Size = UDim2.new(0, 60, 0, 20)
	valueLabel.Position = UDim2.new(1, -60, 0, 0)
	valueLabel.BackgroundTransparency = 1
	valueLabel.Text = tostring(default)
	valueLabel.TextColor3 = Theme.Colors.TextSecondary
	valueLabel.TextSize = Theme.Font.Size.Body
	valueLabel.Font = Theme.Font.Family
	valueLabel.TextXAlignment = Enum.TextXAlignment.Right
	valueLabel.TextYAlignment = Enum.TextYAlignment.Center
	valueLabel.ZIndex = 2

	valueLabel.Parent = sliderFrame

	
	local trackContainer = Instance.new("Frame")
	trackContainer.Name = "TrackContainer"
	trackContainer.Size = UDim2.new(1, 0, 0, 6)
	trackContainer.Position = UDim2.new(0, 0, 1, -16)
	trackContainer.BackgroundTransparency = 1
	trackContainer.ZIndex = 2

	trackContainer.Parent = sliderFrame

	
	local track = Instance.new("Frame")
	track.Name = "Track"
	track.Size = UDim2.new(1, 0, 1, 0)
	track.Position = UDim2.new(0, 0, 0, 0)
	track.BackgroundColor3 = Theme.Colors.BackgroundTertiary
	track.BackgroundTransparency = Theme.Transparency.BackgroundTertiary
	track.ZIndex = 2

	local trackCorner = Utils.CreateCorner(3, track)
	track.Parent = trackContainer

	
	local progress = Instance.new("Frame")
	progress.Name = "Progress"
	progress.Size = UDim2.new(0, 0, 1, 0)
	progress.Position = UDim2.new(0, 0, 0, 0)
	progress.BackgroundColor3 = Theme.Colors.AccentPrimary
	progress.BackgroundTransparency = 0.2
	progress.ZIndex = 2

	local progressCorner = Utils.CreateCorner(3, progress)
	progress.Parent = track

	
	local thumb = Instance.new("Frame")
	thumb.Name = "Thumb"
	thumb.Size = UDim2.new(0, 16, 0, 16)
	thumb.Position = UDim2.new(0, 0, 0.5, -8)
	thumb.BackgroundColor3 = Theme.Colors.AccentPrimary
	thumb.ZIndex = 3
	thumb.ClipsDescendants = true

	local thumbCorner = Utils.CreateCorner(8, thumb)
	local thumbStroke = Utils.CreateStroke(thumb, Theme.Colors.AccentPrimary, 2, 0)

	thumb.Parent = trackContainer

	
	local sliderState = {
		Frame = sliderFrame,
		Track = track,
		Progress = progress,
		Thumb = thumb,
		ValueLabel = valueLabel,
		Min = min,
		Max = max,
		CurrentValue = default,
		Step = step,
		Callback = callback,
		IsDragging = false,
	}

	
	local function updateSlider(value)
		local clampedValue = math.clamp(value, min, max)
		local percent = (clampedValue - min) / (max - min)

		
		progress.Size = UDim2.new(percent, 0, 1, 0)

		
		thumb.Position = UDim2.new(percent, -8, 0.5, -8)

		
		local displayValue = math.round(clampedValue / step) * step
		valueLabel.Text = tostring(displayValue)

		sliderState.CurrentValue = displayValue
	end

	
	local function handleInput(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			sliderState.IsDragging = true

			
			Utils.Tween(thumb, {
				Size = UDim2.new(0, 20, 0, 20),
				Position = UDim2.new(thumb.Position.X.Scale, thumb.Position.X.Offset - 2, 0.5, -10),
			}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

			local connection
			connection = RunService.Heartbeat:Connect(function()
				if not sliderState.IsDragging then
					connection:Disconnect()
					return
				end

				local mousePos = UserInputService:GetMouseLocation()
				local trackPos = track.AbsolutePosition.X
				local trackWidth = track.AbsoluteSize.X

				local relativeX = math.clamp(mousePos.X - trackPos, 0, trackWidth)
				local percent = relativeX / trackWidth
				local value = min + percent * (max - min)

				updateSlider(value)
				callback(math.round(value / step) * step)
			end)

			input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					sliderState.IsDragging = false
					connection:Disconnect()

					
					Utils.Tween(thumb, {
						Size = UDim2.new(0, 16, 0, 16),
						Position = UDim2.new(thumb.Position.X.Scale, thumb.Position.X.Offset + 2, 0.5, -8),
					}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
				end
			end)
		end
	end

	track.InputBegan:Connect(handleInput)
	thumb.InputBegan:Connect(handleInput)

	
	track.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement then
			Utils.Tween(thumb, {
				Size = UDim2.new(0, 18, 0, 18),
				Position = UDim2.new(thumb.Position.X.Scale, thumb.Position.X.Offset - 1, 0.5, -9),
			}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		end
	end)

	track.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement and not sliderState.IsDragging then
			Utils.Tween(thumb, {
				Size = UDim2.new(0, 16, 0, 16),
				Position = UDim2.new(thumb.Position.X.Scale, thumb.Position.X.Offset + 1, 0.5, -8),
			}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		end
	end)

	
	updateSlider(default)

	
	function sliderState:SetValue(value: number)
		updateSlider(value)
		callback(math.round(value / step) * step)
	end

	function sliderState:GetValue(): number
		return sliderState.CurrentValue
	end

	function sliderState:SetCallback(newCallback: (number) -> ())
		sliderState.Callback = newCallback
	end

	function sliderState:Destroy()
		Utils.Tween(sliderFrame, {
			Transparency = 1,
			Size = UDim2.new(0.5, 0, 0, 0),
			Position = UDim2.new(0.25, 0, 0.5, 0),
		}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

		task.delay(0.2, function()
			sliderFrame:Destroy()
		end)
	end

	
	sliderFrame.Parent = parent

	return sliderState
end

return Slider
end

modules["components/inputs/textbox"] = function()



local TextBox = {}
TextBox.__index = TextBox

local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")


function TextBox.Create(config: table)
	config = config or {}
	local parent = config.Parent
	local text = config.Text or ""
	local placeholder = config.Placeholder or "Enter text..."
	local width = config.Width or UDim2.new(1, 0, 0, 40)
	local callback = config.Callback or function() end
	local numbersOnly = config.NumbersOnly or false

	if not parent then
		error("TextBox requires a parent frame")
	end

	
	local textboxFrame = Instance.new("Frame")
	textboxFrame.Name = ("TextBox_" .. tostring(text))
	textboxFrame.Size = width
	textboxFrame.BackgroundColor3 = Theme.Colors.BackgroundTertiary
	textboxFrame.BackgroundTransparency = Theme.Transparency.BackgroundTertiary
	textboxFrame.ZIndex = 2
	textboxFrame.ClipsDescendants = true

	local frameCorner = Utils.CreateCorner(Theme.CornerRadius.WidgetOuter, textboxFrame)
	local frameStroke = Utils.CreateStroke(textboxFrame, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

	
	local glowFrame = Instance.new("Frame")
	glowFrame.Name = "Glow"
	glowFrame.Size = UDim2.new(1, -2, 1, -2)
	glowFrame.Position = UDim2.new(0, 1, 0, 1)
	glowFrame.BackgroundColor3 = Theme.Colors.AccentPrimary
	glowFrame.BackgroundTransparency = 1
	glowFrame.ZIndex = 1
	glowFrame.ClipsDescendants = true

	local glowCorner = Utils.CreateCorner(Theme.CornerRadius.WidgetInner, glowFrame)
	glowFrame.Parent = textboxFrame

	
	local textbox = Instance.new("TextBox")
	textbox.Name = "Input"
	textbox.Size = UDim2.new(1, -16, 1, 0)
	textbox.Position = UDim2.new(0, 8, 0, 0)
	textbox.BackgroundTransparency = 1
	textbox.Text = text
	textbox.PlaceholderText = placeholder
	textbox.TextColor3 = Theme.Colors.TextPrimary
	textbox.PlaceholderColor3 = Theme.Colors.TextMuted
	textbox.TextSize = Theme.Font.Size.Body
	textbox.Font = Theme.Font.Family
	textbox.TextXAlignment = Enum.TextXAlignment.Left
	textbox.ZIndex = 3

	textbox.Parent = textboxFrame

	
	local cursorVisible = true
	local cursorConnection = RunService.Heartbeat:Connect(function()
		if textbox:IsFocused() then
			cursorVisible = not cursorVisible
			textbox.PlaceholderColor3 = cursorVisible and Theme.Colors.TextMuted or Theme.Colors.TextPrimary
		end
	end)

	
	local textboxState = {
		Frame = textboxFrame,
		GlowFrame = glowFrame,
		TextBox = textbox,
		Callback = callback,
		NumbersOnly = numbersOnly,
	}

	
	textbox.Focused:Connect(function()
		
		Utils.Tween(glowFrame, {
			BackgroundTransparency = 0.8,
		}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

		
		Utils.Tween(textboxFrame, {
			BackgroundColor3 = Theme.Colors.BackgroundHover,
			BackgroundTransparency = Theme.Transparency.BackgroundHover,
		}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
	end)

	
	textbox.FocusLost:Connect(function(enterPressed)
		
		Utils.Tween(glowFrame, {
			BackgroundTransparency = 1,
		}, 0.3, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

		
		Utils.Tween(textboxFrame, {
			BackgroundColor3 = Theme.Colors.BackgroundTertiary,
			BackgroundTransparency = Theme.Transparency.BackgroundTertiary,
		}, 0.3, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

		
		if enterPressed then
			task.spawn(callback, textbox.Text)
		end
	end)

	
	textbox:GetPropertyChangedSignal("Text"):Connect(function()
		if textboxState.NumbersOnly then
			
			local filtered = textbox.Text:gsub("[^0-9]", "")
			if filtered ~= textbox.Text then
				textbox.Text = filtered
			end
		end
	end)

	
	function textboxState:SetText(newText: string)
		textbox.Text = newText
	end

	function textboxState:GetText(): string
		return textbox.Text
	end

	function textboxState:SetPlaceholder(newPlaceholder: string)
		textbox.PlaceholderText = newPlaceholder
	end

	function textboxState:SetCallback(newCallback: (string) -> ())
		textboxState.Callback = newCallback
	end

	function textboxState:Clear()
		textbox.Text = ""
	end

	function textboxState:Focus()
		textbox:CaptureFocus()
	end

	function textboxState:Destroy()
		cursorConnection:Disconnect()

		Utils.Tween(textboxFrame, {
			Transparency = 1,
			Size = UDim2.new(0.5, 0, 0, 0),
			Position = UDim2.new(0.25, 0, 0.5, 0),
		}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

		task.delay(0.2, function()
			textboxFrame:Destroy()
		end)
	end

	
	textboxFrame.Parent = parent

	return textboxState
end

return TextBox
end

modules["components/inputs/toggle"] = function()



local Toggle = {}
Toggle.__index = Toggle

local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")


function Toggle.Create(config: table)
	config = config or {}
	local parent = config.Parent
	local text = config.Text or "Toggle"
	local defaultState = config.Default or false
	local callback = config.Callback or function() end

	if not parent then
		error("Toggle requires a parent frame")
	end

	
	local toggleFrame = Instance.new("Frame")
	toggleFrame.Name = ("Toggle_" .. tostring(text))
	toggleFrame.Size = UDim2.new(1, 0, 0, 36)
	toggleFrame.BackgroundTransparency = 1
	toggleFrame.ZIndex = 2

	
	local outerShell = Instance.new("Frame")
	outerShell.Name = "OuterShell"
	outerShell.Size = UDim2.new(0, 44, 0, 24)
	outerShell.Position = UDim2.new(1, -52, 0.5, -12)
	outerShell.BackgroundColor3 = Theme.Colors.BackgroundTertiary
	outerShell.BackgroundTransparency = Theme.Transparency.BackgroundTertiary
	outerShell.ZIndex = 2
	outerShell.ClipsDescendants = true

	local outerCorner = Utils.CreateCorner(12, outerShell)
	local outerStroke = Utils.CreateStroke(outerShell, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

	outerShell.Parent = toggleFrame

	
	local sliderPill = Instance.new("Frame")
	sliderPill.Name = "SliderPill"
	sliderPill.Size = UDim2.new(0, 18, 0, 18)
	sliderPill.Position = UDim2.new(0, 3, 0.5, -9)
	sliderPill.BackgroundColor3 = Theme.Colors.TextSecondary
	sliderPill.ZIndex = 3
	sliderPill.ClipsDescendants = true

	local sliderCorner = Utils.CreateCorner(9, sliderPill)

	sliderPill.Parent = outerShell

	
	local textLabel = Instance.new("TextLabel")
	textLabel.Name = "Text"
	textLabel.Size = UDim2.new(1, -60, 1, 0)
	textLabel.Position = UDim2.new(0, 0, 0, 0)
	textLabel.BackgroundTransparency = 1
	textLabel.Text = text
	textLabel.TextColor3 = Theme.Colors.TextPrimary
	textLabel.TextSize = Theme.Font.Size.Body
	textLabel.Font = Theme.Font.Family
	textLabel.TextXAlignment = Enum.TextXAlignment.Left
	textLabel.TextYAlignment = Enum.TextYAlignment.Center
	textLabel.ZIndex = 2

	textLabel.Parent = toggleFrame

	
	local toggleState = {
		Frame = toggleFrame,
		OuterShell = outerShell,
		SliderPill = sliderPill,
		TextLabel = textLabel,
		IsOn = defaultState,
		Callback = callback,
	}

	
	local function updateVisual(state)
		if state then
			
			Utils.Tween(outerShell, {
				BackgroundColor3 = Theme.Colors.AccentPrimary,
				BackgroundTransparency = 0.3,
			}, 0.25, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

			Utils.Tween(sliderPill, {
				Position = UDim2.new(1, -21, 0.5, -9),
				Size = UDim2.new(0, 18, 0, 18),
			}, 0.25, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		else
			
			Utils.Tween(outerShell, {
				BackgroundColor3 = Theme.Colors.BackgroundTertiary,
				BackgroundTransparency = Theme.Transparency.BackgroundTertiary,
			}, 0.25, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

			Utils.Tween(sliderPill, {
				Position = UDim2.new(0, 3, 0.5, -9),
				Size = UDim2.new(0, 18, 0, 18),
			}, 0.25, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
		end
	end

	
	outerShell.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			
			Utils.Tween(sliderPill, {
				Size = UDim2.new(0, 14, 0, 14),
			}, 0.1, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

			input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					
					Utils.Tween(sliderPill, {
						Size = UDim2.new(0, 18, 0, 18),
					}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

					
					toggleState.IsOn = not toggleState.IsOn
					updateVisual(toggleState.IsOn)

					
					task.spawn(callback, toggleState.IsOn)
				end
			end)
		end
	end)

	
	outerShell.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement then
			if not toggleState.IsOn then
				Utils.Tween(outerShell, {
					BackgroundColor3 = Theme.Colors.BackgroundHover,
					BackgroundTransparency = Theme.Transparency.BackgroundHover,
				}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
			end
		end
	end)

	outerShell.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement then
			if not toggleState.IsOn then
				Utils.Tween(outerShell, {
					BackgroundColor3 = Theme.Colors.BackgroundTertiary,
					BackgroundTransparency = Theme.Transparency.BackgroundTertiary,
				}, 0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
			end
		end
	end)

	
	updateVisual(defaultState)

	
	function toggleState:SetState(state: boolean)
		toggleState.IsOn = state
		updateVisual(state)
	end

	function toggleState:GetState(): boolean
		return toggleState.IsOn
	end

	function toggleState:SetCallback(newCallback: (boolean) -> ())
		toggleState.Callback = newCallback
	end

	function toggleState:Destroy()
		Utils.Tween(toggleFrame, {
			Transparency = 1,
			Size = UDim2.new(0.5, 0, 0, 0),
			Position = UDim2.new(0.25, 0, 0.5, 0),
		}, 0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

		task.delay(0.2, function()
			toggleFrame:Destroy()
		end)
	end

	
	toggleFrame.Parent = parent

	return toggleState
end

return Toggle
end

