modules["components/layout/row"] = function()



local Row = {}
Row.__index = Row

local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")


function Row.Create(config: table)
	config = config or {}
	local parent = config.Parent
	local gap = config.Gap or Theme.Spacing.SM
	local items = config.Items or {}

	if not parent then
		error("Row requires a parent frame")
	end

	
	local rowFrame = Instance.new("Frame")
	rowFrame.Name = "Row"
	rowFrame.Size = UDim2.new(1, 0, 0, 0)
	rowFrame.BackgroundTransparency = 1
	rowFrame.ZIndex = 2

	
	local layout = Instance.new("UIListLayout")
	layout.FillDirection = Enum.FillDirection.Horizontal
	layout.HorizontalAlignment = Enum.HorizontalAlignment.Center
	layout.VerticalAlignment = Enum.VerticalAlignment.Center
	layout.Padding = UDim.new(0, gap)
	layout.SortOrder = Enum.SortOrder.LayoutOrder
	layout.Parent = rowFrame

	
	local rowState = {
		Frame = rowFrame,
		Layout = layout,
		Gap = gap,
		Items = {},
	}

	
	for i, item in ipairs(items) do
		if typeof(item) == "Instance" then
			item.LayoutOrder = i
			item.Parent = rowFrame
			table.insert(rowState.Items, item)
		end
	end

	
	function rowState:AddItem(item: Instance)
		if typeof(item) == "Instance" then
			item.LayoutOrder = #self.Items + 1
			item.Parent = self.Frame
			table.insert(self.Items, item)
		end
		return self
	end

	function rowState:RemoveItem(item: Instance)
		for i, existingItem in ipairs(self.Items) do
			if existingItem == item then
				table.remove(self.Items, i)
				item:Destroy()
				break
			end
		end
		return self
	end

	function rowState:Clear()
		for _, item in ipairs(self.Items) do
			if item and item.Parent then
				item:Destroy()
			end
		end
		table.clear(self.Items)
		return self
	end

	
	rowFrame.Parent = parent

	
	task.wait(0.01)
	rowFrame.Size = UDim2.new(1, 0, 0, rowFrame.AbsoluteContentSize.Y)

	return rowState
end

return Row
end

