local CustomIcons = {}


function Icons.Register(name: string, assetId: string, weight: string?)
	local weight = weight or "Regular"
	Icons.Registry[name] = {
		AssetId = assetId,
		Weight = weight,
	}
	return Icons
end


function Icons.RegisterBatch(icons: table, weight: string?)
	for name, assetId in pairs(icons) do
		Icons.Register(name, assetId, weight)
	end
	return Icons
end


function Icons.LoadPreset(presetName: string)
	if presetName == "Phosphor" then
		Icons.LoadedPresets.PhosphorRegular = PhosphorRegular
		Icons.LoadedPresets.PhosphorFilled = PhosphorFilled
		Icons.ActivePreset = "Phosphor"
	elseif presetName == "Material" then
		Icons.LoadedPresets.Material = MaterialIcons
		Icons.ActivePreset = "Material"
	elseif presetName == "Custom" then
		Icons.ActivePreset = "Custom"
	end

	return Icons
end


function Icons.Get(name: string, weight: string?): string?
	weight = weight or "Regular"

	if Icons.ActivePreset == "Phosphor" then
		if weight == "Filled" then
			return PhosphorFilled[name]
		else
			return PhosphorRegular[name]
		end
	elseif Icons.ActivePreset == "Material" then
		return MaterialIcons[name]
	elseif Icons.ActivePreset == "Custom" then
		return Icons.Registry[name] and Icons.Registry[name].AssetId
	end

	return nil
end


function Icons.Create(
	name: string,
	parent: Instance?,
	size: UDim2?,
	position: UDim2?,
	color: Color3?,
	transparency: number?,
	weight: string?
): ImageLabel
	local assetId = Icons.Get(name, weight)
	if not assetId then
		warn(("Icon \"" .. tostring(name) .. "\" not found in preset " .. tostring(Icons.ActivePreset)))
		return nil
	end

	local image = Instance.new("ImageLabel")
	image.Name = name
	image.Size = size or UDim2.new(0, 24, 0, 24)
	image.Position = position or UDim2.new(0, 0, 0, 0)
	image.BackgroundTransparency = 1
	image.Image = assetId
	image.ImageColor3 = color or Color3.new(1, 1, 1)
	image.ImageTransparency = transparency or 0

	if parent then
		image.Parent = parent
	end

	return image
end


function Icons.CreatePill(
	name: string,
	parent: Instance?,
	size: number?,
	color: Color3?,
	transparency: number?,
	weight: string?
): Frame
	local pillSize = size or 22

	local pill = Instance.new("Frame")
	pill.Name = (tostring(name) .. "Pill")
	pill.Size = UDim2.new(0, pillSize, 0, pillSize)
	pill.BackgroundColor3 = color or Color3.fromHex("#7c3aed")
	pill.BackgroundTransparency = transparency or 0.85

	local corner = Instance.new("UICorner")
	corner.CornerRadius = UDim.new(1, 0)
	corner.Parent = pill

	
	local icon = Icons.Create(
		name,
		pill,
		UDim2.new(0, pillSize - 6, 0, pillSize - 6),
		UDim2.new(0.5, -(pillSize - 6) / 2, 0.5, -(pillSize - 6) / 2),
		Color3.new(1, 1, 1),
		0,
		weight
	)

	if parent then
		pill.Parent = parent
	end

	return pill
end


function Icons.Exists(name: string, weight: string?): boolean
	return Icons.Get(name, weight) ~= nil
end


function Icons.GetAvailable(): {string}
	if Icons.ActivePreset == "Phosphor" then
		local regularKeys = {}
		for key, _ in pairs(PhosphorRegular) do
			table.insert(regularKeys, key)
		end
		return regularKeys
	elseif Icons.ActivePreset == "Material" then
		local materialKeys = {}
		for key, _ in pairs(MaterialIcons) do
			table.insert(materialKeys, key)
		end
		return materialKeys
	elseif Icons.ActivePreset == "Custom" then
		local customKeys = {}
		for key, _ in pairs(Icons.Registry) do
			table.insert(customKeys, key)
		end
		return customKeys
	end
	return {}
end


Icons.LoadPreset("Phosphor")

return Icons
end

modules["core/notification"] = function()



local Notification = {}
Notification.__index = Notification

local Players = game:GetService("Players")
local TweenService = game:GetService("TweenService")
local RunService = game:GetService("RunService")

local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")
local Icons = custom_require("core/icons")


Notification.Registry = {}
Notification.NextId = 1
Notification._gui = nil



local function getNotificationGui(): Instance
	if not Notification._gui or not Notification._gui.Parent then
		Notification._gui = Utils.CreateScreenGui("QwenUILib_Notifications")
	end
	return Notification._gui
end


Notification.Types = {
	Info = { Color = Theme.Colors.Info, Icon = "info" },
	Success = { Color = Theme.Colors.Success, Icon = "check-circle" },
	Warning = { Color = Theme.Colors.Warning, Icon = "warning-circle" },
	Error = { Color = Theme.Colors.Error, Icon = "x-circle" },
}


function Notification.Create(message: string, type: string?, parent: Instance?)
	type = type or "Info"
	local notifData = Notification.Types[type] or Notification.Types.Info

	
	
	if typeof(parent) ~= "Instance" then
		parent = getNotificationGui()
	end

	
	local container = Instance.new("Frame")
	container.Name = ("Notification_" .. tostring(Notification.NextId))
	container.Size = UDim2.new(1, -40, 0, 64)
	container.Position = UDim2.new(0, 20, 1, 100)
	container.BackgroundColor3 = Theme.Colors.BackgroundSecondary
	container.BackgroundTransparency = Theme.Transparency.BackgroundSecondary
	container.ZIndex = 100

	local containerCorner = Utils.CreateCorner(Theme.CornerRadius.WidgetOuter, container)
	local containerStroke = Utils.CreateStroke(container, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

	
	local glass = Instance.new("Frame")
	glass.Name = "Glass"
	glass.Size = UDim2.new(1, 0, 1, 0)
	glass.Position = UDim2.new(0, 0, 0, 0)
	glass.BackgroundColor3 = Color3.new(1, 1, 1)
	glass.BackgroundTransparency = 0.93
	glass.ZIndex = 1

	local glassCorner = Utils.CreateCorner(Theme.CornerRadius.WidgetInner, glass)
	glass.Parent = container

	
	local glowBar = Instance.new("Frame")
	glowBar.Name = "GlowBar"
	glowBar.Size = UDim2.new(0, 4, 1, 0)
	glowBar.Position = UDim2.new(0, 0, 0, 0)
	glowBar.BackgroundColor3 = notifData.Color
	glowBar.BackgroundTransparency = 0.2
	glowBar.ZIndex = 2

	local glowCorner = Utils.CreateCorner(2, glowBar)
	glowBar.Parent = container

	
	local iconPill = Icons.CreatePill(
		notifData.Icon,
		container,
		36,
		notifData.Color,
		0.85,
		"Filled"
	)
	iconPill.Position = UDim2.new(0, 12, 0.5, -18)
	iconPill.ZIndex = 3

	
	local messageText = Instance.new("TextLabel")
	messageText.Name = "Message"
	messageText.Size = UDim2.new(1, -70, 0, 20)
	messageText.Position = UDim2.new(0, 58, 0.5, -10)
	messageText.BackgroundTransparency = 1
	messageText.Text = message
	messageText.TextColor3 = Theme.Colors.TextPrimary
	messageText.TextSize = Theme.Font.Size.Body
	messageText.Font = Theme.Font.Family
	messageText.TextXAlignment = Enum.TextXAlignment.Left
	messageText.TextYAlignment = Enum.TextYAlignment.Center
	messageText.ZIndex = 3

	messageText.Parent = container

	
	local closeButton = Instance.new("TextButton")
	closeButton.Name = "CloseButton"
	closeButton.Size = UDim2.new(0, 24, 0, 24)
	closeButton.Position = UDim2.new(1, -32, 0.5, -12)
	closeButton.BackgroundTransparency = 1
	closeButton.Text = ""
	closeButton.ZIndex = 3

	local closeIcon = Icons.Create(
		"x",
		closeButton,
		UDim2.new(0, 16, 0, 16),
		UDim2.new(0.5, -8, 0.5, -8),
		Theme.Colors.TextMuted,
		0.6
	)

	closeButton.Parent = container

	
	local progressBar = Instance.new("Frame")
	progressBar.Name = "ProgressBar"
	progressBar.Size = UDim2.new(1, 0, 0, 3)
	progressBar.Position = UDim2.new(0, 0, 1, -3)
	progressBar.BackgroundColor3 = Theme.Colors.BorderPrimary
	progressBar.BackgroundTransparency = Theme.Transparency.Border
	progressBar.ZIndex = 3

	local progressCorner = Utils.CreateCorner(1, progressBar)
	progressBar.Parent = container

	local progressFill = Instance.new("Frame")
	progressFill.Name = "ProgressFill"
	progressFill.Size = UDim2.new(0, 0, 1, 0)
	progressFill.Position = UDim2.new(0, 0, 0, 0)
	progressFill.BackgroundColor3 = notifData.Color
	progressFill.BackgroundTransparency = 0.3
	progressFill.ZIndex = 4

	local fillCorner = Utils.CreateCorner(1, progressFill)
	progressFill.Parent = progressBar

	
	container.Parent = parent

	
	local notifState = {
		Container = container,
		MessageText = messageText,
		ProgressFill = progressFill,
		Id = Notification.NextId,
		Type = type,
		Duration = 4,
		StartTime = os.clock(),
	}

	
	container.Position = UDim2.new(0, 20, 1, 100)

	Utils.Tween(container, {
		Position = UDim2.new(0, 20, 1, -84),
	}, 0.5, Enum.EasingStyle.Back, Enum.EasingDirection.Out)

	
	local function close()
		
		Utils.Tween(container, {
			Position = UDim2.new(0, 20, 1, 100),
			Transparency = 1,
		}, 0.3, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

		task.delay(0.3, function()
			container:Destroy()
			Notification.Registry[notifState] = nil
		end)
	end

	closeButton.MouseButton1Click:Connect(close)

	
	task.delay(notifState.Duration, function()
		if notifState.Container and notifState.Container.Parent then
			close()
		end
	end)

	
	local isPaused = false
	local elapsedBeforePause = 0

	container.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement then
			
			isPaused = true
			elapsedBeforePause = os.clock() - notifState.StartTime
		end
	end)

	container.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement then
			
			isPaused = false
			notifState.StartTime = os.clock() - elapsedBeforePause
		end
	end)

	
	
	
	local progressConnection
	progressConnection = RunService.Heartbeat:Connect(function()
		if isPaused then
			
			return
		end

		local elapsed = os.clock() - notifState.StartTime
		local progress = math.clamp(elapsed / notifState.Duration, 0, 1)
		progressFill.Size = UDim2.new(progress, 0, 1, 0)

		if progress >= 1 then
			progressConnection:Disconnect()
		end
	end)

	notifState.ProgressConnection = progressConnection

	
	Notification.Registry[notifState] = notifState
	Notification.NextId = Notification.NextId + (1)

	return notifState
end


function Notification.DismissAll()
	for notifState, _ in pairs(Notification.Registry) do
		if notifState.Container and notifState.Container.Parent then
			notifState.Container:Destroy()
		end
	end
	table.clear(Notification.Registry)
end


function Notification.Dismiss(id: number)
	for notifState, _ in pairs(Notification.Registry) do
		if notifState.Id == id then
			if notifState.Container and notifState.Container.Parent then
				notifState.Container:Destroy()
			end
			Notification.Registry[notifState] = nil
			break
		end
	end
end

return Notification
end

