modules["core/utils"] = function()



local Utils = {}
Utils.__index = Utils


function Utils.Tween(object: Instance, properties: table, duration: number, easingStyle: Enum.EasingStyle?, easingDirection: Enum.EasingDirection?): Tween
	local tweenService = game:GetService("TweenService")

	easingStyle = easingStyle or Enum.EasingStyle.Quart
	easingDirection = easingDirection or Enum.EasingDirection.Out

	local tweenInfo = TweenInfo.new(
		duration,
		easingStyle,
		easingDirection
	)

	local tween = tweenService:Create(object, tweenInfo, properties)
	tween:Play()

	return tween
end


function Utils.CreateCorner(radius: number, parent: Instance?): UICorner
	local corner = Instance.new("UICorner")
	corner.CornerRadius = UDim.new(0, radius)
	if parent then
		corner.Parent = parent
	end
	return corner
end


function Utils.CreateStroke(
	parent: Instance,
	color: Color3?,
	thickness: number?,
	transparency: number?,
	cornerRadius: number?
): UIStroke
	local stroke = Instance.new("UIStroke")
	stroke.Color = color or Color3.fromHex("#3f3f46")
	stroke.Thickness = thickness or 1
	stroke.Transparency = transparency or 0.8
	stroke.LineJoinMode = Enum.LineJoinMode.Round

	if cornerRadius then
		stroke.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
		local corner = Utils.CreateCorner(cornerRadius, parent)
	end

	stroke.Parent = parent
	return stroke
end


function Utils.MakeDraggable(frame: Frame, dragHandle: Frame?)
	local dragTarget = dragHandle or frame
	local dragging = false
	local dragInput = nil
	local dragStart = nil
	local startPos = nil

	local function updatePosition(input)
		local delta = input.Position - dragStart
		frame.Position = UDim2.new(
			startPos.X.Scale,
			startPos.X.Offset + delta.X,
			startPos.Y.Scale,
			startPos.Y.Offset + delta.Y
		)
	end

	dragTarget.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			dragging = true
			dragStart = input.Position
			startPos = frame.Position

			input.Changed:Connect(function()
				if input.UserInputState == Enum.UserInputState.End then
					dragging = false
				end
			end)
		end
	end)

	dragTarget.InputChanged:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
			dragInput = input
		end
	end)

	game:GetService("UserInputService").InputChanged:Connect(function(input)
		if input == dragInput and dragging then
			updatePosition(input)
		end
	end)

	return frame
end


function Utils.CreateShadow(parent: Instance, size: number?, transparency: number?): Frame
	local shadow = Instance.new("Frame")
	shadow.Name = "Shadow"
	shadow.Size = UDim2.new(1, size or 20, 1, size or 20)
	shadow.Position = UDim2.new(0, -(size or 20) / 2, 0, -(size or 20) / 2)
	shadow.BackgroundTransparency = 1
	shadow.ZIndex = parent.ZIndex - 1

	local image = Instance.new("ImageLabel")
	image.Name = "ShadowImage"
	image.Size = UDim2.new(1, 0, 1, 0)
	image.Position = UDim2.new(0, 0, 0, 0)
	image.BackgroundTransparency = 1
	image.Image = "rbxassetid://6403377997" 
	image.ImageColor3 = Color3.fromHex("#000000")
	image.ImageTransparency = transparency or 0.5
	image.ScaleType = Enum.ScaleType.Slice
	image.SliceCenter = Rect.new(50, 50, 50, 50)
	image.SliceScale = 2

	image.Parent = shadow
	shadow.Parent = parent

	return shadow
end


function Utils.CreateGlowBlob(
	parent: Instance,
	color: Color3?,
	size: number?,
	position: UDim2?
): Frame
	local blob = Instance.new("Frame")
	blob.Name = "GlowBlob"
	blob.Size = UDim2.new(0, size or 200, 0, size or 200)
	blob.Position = position or UDim2.new(0.5, -100, 0.5, -100)
	blob.BackgroundColor3 = color or Color3.fromHex("#7c3aed")
	blob.BackgroundTransparency = 0.85
	blob.ZIndex = 1

	local corner = Utils.CreateCorner(50, blob)
	local blur = Instance.new("BlurEffect")
	blur.Size = 64
	blur.Parent = blob

	blob.Parent = parent

	
	local runService = game:GetService("RunService")
	local startTime = os.clock()

	local connection = runService.Heartbeat:Connect(function()
		local elapsed = os.clock() - startTime
		blob.Position = UDim2.new(
			0.5 + math.sin(elapsed * 0.5) * 0.1,
			-size / 2,
			0.5 + math.cos(elapsed * 0.3) * 0.1,
			-size / 2
		)
	end)

	blob:GetPropertyChangedSignal("Parent"):Connect(function()
		if not blob.Parent then
			connection:Disconnect()
		end
	end)

	return blob
end


function Utils.CreateListLayout(
	parent: Instance,
	horizontal: boolean?,
	padding: number?,
	align: Enum.FlexAlignment?
): UIListLayout
	local layout = Instance.new("UIListLayout")
	layout.FillDirection = horizontal and Enum.FillDirection.Horizontal or Enum.FillDirection.Vertical
	layout.HorizontalAlignment = align or Enum.FlexAlignment.Center
	layout.VerticalAlignment = align or Enum.FlexAlignment.Center
	layout.Padding = UDim.new(0, padding or 8)
	layout.SortOrder = Enum.SortOrder.LayoutOrder
	layout.Parent = parent

	return layout
end


function Utils.CreatePadding(
	parent: Instance,
	top: number?,
	bottom: number?,
	left: number?,
	right: number?
): UIPadding
	local padding = Instance.new("UIPadding")
	padding.PaddingTop = UDim.new(0, top or 0)
	padding.PaddingBottom = UDim.new(0, bottom or 0)
	padding.PaddingLeft = UDim.new(0, left or 0)
	padding.PaddingRight = UDim.new(0, right or 0)
	padding.Parent = parent

	return padding
end


function Utils.CreateScale(parent: Instance, scale: number?): UIScale
	local scaleObj = Instance.new("UIScale")
	scaleObj.Scale = scale or 1
	scaleObj.Parent = parent

	return scaleObj
end


function Utils.ApplyTheme(
	frame: Frame,
	backgroundColor: Color3?,
	backgroundTransparency: number?,
	cornerRadius: number?
): Frame
	if backgroundColor then
		frame.BackgroundColor3 = backgroundColor
	end
	if backgroundTransparency then
		frame.BackgroundTransparency = backgroundTransparency
	end
	if cornerRadius then
		local corner = Utils.CreateCorner(cornerRadius, frame)
	end

	return frame
end


function Utils.Clamp(value: number, min: number, max: number): number
	return math.clamp(value, min, max)
end


function Utils.Lerp(start: number, goal: number, alpha: number): number
	return start + (goal - start) * alpha
end


function Utils.Map(value: number, inMin: number, inMax: number, outMin: number, outMax: number): number
	return (value - inMin) * (outMax - outMin) / (inMax - inMin) + outMin
end


function Utils.Debounce(func: any, delay: number): any
	local running = false
	return function(...)
		if not running then
			running = true
			
			
			local args = table.pack(...)
			task.delay(delay, function()
				running = false
				func(table.unpack(args, 1, args.n))
			end)
		end
	end
end


function Utils.Throttle(func: any, limit: number): any
	local lastExecution = 0
	return function(...)
		local now = os.clock()
		if now - lastExecution >= limit then
			lastExecution = now
			func(...)
		end
	end
end


function Utils.DeepMerge(original: table, new: table): table
	for key, value in pairs(new) do
		if type(value) == "table" and type(original[key]) == "table" then
			Utils.DeepMerge(original[key], value)
		else
			original[key] = value
		end
	end
	return original
end




function Utils.GetGuiParent(): Instance
	local ok, hui = pcall(function()
		if typeof(gethui) == "function" then
			return gethui()
		end
		return nil
	end)
	if ok and hui then
		return hui
	end

	local coreOk, coreGui = pcall(function()
		return game:GetService("CoreGui")
	end)
	if coreOk and coreGui then
		return coreGui
	end

	local player = game:GetService("Players").LocalPlayer
	if player then
		return player:WaitForChild("PlayerGui")
	end

	error("QwenUILib: no valid GUI container found (no gethui, CoreGui, or PlayerGui)")
end



function Utils.CreateScreenGui(name: string?): ScreenGui
	local screenGui = Instance.new("ScreenGui")
	screenGui.Name = name or "QwenUILib"
	screenGui.ResetOnSpawn = false
	screenGui.IgnoreGuiInset = true
	screenGui.DisplayOrder = 999

	
	pcall(function()
		screenGui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
	end)

	local parent = Utils.GetGuiParent()

	
	pcall(function()
		if syn and syn.protect_gui then
			syn.protect_gui(screenGui)
		elseif typeof(protectgui) == "function" then
			protectgui(screenGui)
		end
	end)

	screenGui.Parent = parent
	return screenGui
end




function Utils.AutoCanvasY(scrollFrame: Instance)
	local enumOk = pcall(function()
		return Enum.AutomaticCanvasSize.Y
	end)

	if enumOk then
		local applied = pcall(function()
			scrollFrame.AutomaticCanvasSize = Enum.AutomaticCanvasSize.Y
		end)
		if applied then
			return
		end
	end

	
	local function bind(layout)
		if not (layout and layout:IsA("UIGridStyleLayout")) then
			return
		end
		local function update()
			local content = layout.AbsoluteContentSize
			scrollFrame.CanvasSize = UDim2.new(0, 0, 0, content.Y)
		end
		layout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(update)
		update()
	end

	local existing = scrollFrame:FindFirstChildWhichIsA("UIGridStyleLayout")
	if existing then
		bind(existing)
	else
		scrollFrame.ChildAdded:Connect(function(child)
			if child:IsA("UIGridStyleLayout") then
				bind(child)
			end
		end)
	end
end




function Utils.SafeAutoSize(obj: Instance, axis: string?, property: string?)
	axis = axis or "Y"
	property = property or "AutomaticSize"
	pcall(function()
		obj[property] = Enum.AutomaticSize[axis]
	end)
end


function Utils.CreateCleanupWrapper(object: Instance, cleanupFunc: () -> ())
	local mt = {
		__gc = function()
			cleanupFunc()
		end,
	}

	if typeof(object) == "Instance" then
		object:GetPropertyChangedSignal("Parent"):Connect(function()
			if not object.Parent then
				cleanupFunc()
			end
		end)
	end

	return setmetatable({}, mt)
end

return Utils
end

modules["core/window"] = function()



local Window = {}
Window.__index = Window

local Players = game:GetService("Players")
local TweenService = game:GetService("TweenService")
local UserInputService = game:GetService("UserInputService")
local RunService = game:GetService("RunService")

local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")
local Icons = custom_require("core/icons")


Window.Registry = {}
Window.ActiveWindow = nil


function Window.Create(config: table)
	config = config or {}
	local title = config.Title or "QwenUI Window"
	local width = config.Width or 600
	local height = config.Height or 400
	local minWidth = config.MinWidth or 400
	local minHeight = config.MinHeight or 300

	
	
	local screenGui = nil
	local parent = config.Parent
	if not parent then
		screenGui = Utils.CreateScreenGui("QwenUILib")
		parent = screenGui
	end

	
	local outerFrame = Instance.new("Frame")
	outerFrame.Name = "QwenWindow_Outer"
	outerFrame.Size = UDim2.new(0, width, 0, height)
	outerFrame.Position = UDim2.new(0.5, -width / 2, 0.5, -height / 2)
	outerFrame.BackgroundColor3 = Theme.Colors.BackgroundPrimary
	outerFrame.BackgroundTransparency = Theme.Transparency.BackgroundPrimary
	outerFrame.ZIndex = 1
	outerFrame.ClipsDescendants = true

	
	local outerStroke = Utils.CreateStroke(outerFrame, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Stroke)
	local outerCorner = Utils.CreateCorner(Theme.CornerRadius.WindowOuter, outerFrame)

	
	local innerFrame = Instance.new("Frame")
	innerFrame.Name = "QwenWindow_Inner"
	innerFrame.Size = UDim2.new(1, -12, 1, -12)
	innerFrame.Position = UDim2.new(0, 6, 0, 6)
	innerFrame.BackgroundColor3 = Theme.Colors.BackgroundSecondary
	innerFrame.BackgroundTransparency = Theme.Transparency.BackgroundSecondary
	innerFrame.ZIndex = 1
	innerFrame.ClipsDescendants = true

	local innerCorner = Utils.CreateCorner(Theme.CornerRadius.WindowInner, innerFrame)
	local innerStroke = Utils.CreateStroke(innerFrame, Theme.Colors.BorderSecondary, 1, Theme.Transparency.Border)

	innerFrame.Parent = outerFrame

	
	local glassOverlay = Instance.new("Frame")
	glassOverlay.Name = "GlassOverlay"
	glassOverlay.Size = UDim2.new(1, 0, 1, 0)
	glassOverlay.Position = UDim2.new(0, 0, 0, 0)
	glassOverlay.BackgroundColor3 = Color3.new(1, 1, 1)
	glassOverlay.BackgroundTransparency = 0.95
	glassOverlay.ZIndex = 1

	local glassCorner = Utils.CreateCorner(Theme.CornerRadius.WindowInner, glassOverlay)
	glassOverlay.Parent = innerFrame

	
	local glowBlob = Utils.CreateGlowBlob(
		innerFrame,
		Theme.Colors.AccentPrimary,
		300,
		UDim2.new(0.5, -150, 0.3, -150)
	)

	
	local titleBar = Instance.new("Frame")
	titleBar.Name = "TitleBar"
	titleBar.Size = UDim2.new(1, 0, 0, 40)
	titleBar.Position = UDim2.new(0, 0, 0, 0)
	titleBar.BackgroundTransparency = 1
	titleBar.ZIndex = 3

	local titleCorner = Utils.CreateCorner(Theme.CornerRadius.WindowInner, titleBar)
	titleBar.Parent = innerFrame

	
	local titleText = Instance.new("TextLabel")
	titleText.Name = "Title"
	titleText.Size = UDim2.new(1, -80, 1, 0)
	titleText.Position = UDim2.new(0, 16, 0, 0)
	titleText.BackgroundTransparency = 1
	titleText.Text = title
	titleText.TextColor3 = Theme.Colors.TextPrimary
	titleText.TextSize = Theme.Font.Size.Title
	titleText.Font = Theme.Font.Family
	titleText.TextXAlignment = Enum.TextXAlignment.Left
	titleText.ZIndex = 3

	titleText.Parent = titleBar

	
	local searchFrame = nil
	local searchInput = nil

	if config.SearchEnabled then
		searchFrame = Instance.new("Frame")
		searchFrame.Name = "SearchFrame"
		searchFrame.Size = UDim2.new(0, 180, 0, 28)
		searchFrame.Position = UDim2.new(1, -200, 0.5, -14)
		searchFrame.BackgroundColor3 = Theme.Colors.BackgroundTertiary
		searchFrame.BackgroundTransparency = Theme.Transparency.BackgroundTertiary
		searchFrame.ZIndex = 3

		local searchCorner = Utils.CreateCorner(Theme.CornerRadius.Small, searchFrame)
		local searchStroke = Utils.CreateStroke(searchFrame, Theme.Colors.BorderPrimary, 1, Theme.Transparency.Border)

		searchFrame.Parent = titleBar

		searchInput = Instance.new("TextBox")
		searchInput.Name = "SearchInput"
		searchInput.Size = UDim2.new(1, -32, 1, 0)
		searchInput.Position = UDim2.new(0, 8, 0, 0)
		searchInput.BackgroundTransparency = 1
		searchInput.PlaceholderText = "Search..."
		searchInput.Text = ""
		searchInput.TextColor3 = Theme.Colors.TextPrimary
		searchInput.PlaceholderColor3 = Theme.Colors.TextMuted
		searchInput.TextSize = Theme.Font.Size.Body
		searchInput.Font = Theme.Font.Family
		searchInput.ZIndex = 3

		searchInput.Parent = searchFrame

		
		local searchIcon = Icons.Create(
			"magnifying-glass",
			searchFrame,
			UDim2.new(0, 16, 0, 16),
			UDim2.new(1, -24, 0.5, -8),
			Theme.Colors.TextMuted,
			0.5
		)
	end

	
	local contentContainer = Instance.new("ScrollingFrame")
	contentContainer.Name = "ContentContainer"
	contentContainer.Size = UDim2.new(1, 0, 1, -40)
	contentContainer.Position = UDim2.new(0, 0, 0, 40)
	contentContainer.BackgroundTransparency = 1
	contentContainer.ScrollBarThickness = 4
	contentContainer.ScrollBarImageColor3 = Theme.Colors.AccentPrimary
	contentContainer.ScrollBarImageTransparency = 0.5
	contentContainer.CanvasSize = UDim2.new(0, 0, 0, 0)
	Utils.AutoCanvasY(contentContainer)
	contentContainer.ZIndex = 2
	contentContainer.ClipsDescendants = true

	local contentCorner = Utils.CreateCorner(Theme.CornerRadius.WindowInner, contentContainer)
	contentContainer.Parent = innerFrame

	
	local contentPadding = Instance.new("UIPadding")
	contentPadding.PaddingTop = UDim.new(0, 16)
	contentPadding.PaddingBottom = UDim.new(0, 16)
	contentPadding.PaddingLeft = UDim.new(0, 16)
	contentPadding.PaddingRight = UDim.new(0, 16)
	contentPadding.Parent = contentContainer

	
	local contentLayout = Instance.new("UIListLayout")
	contentLayout.FillDirection = Enum.FillDirection.Vertical
	contentLayout.HorizontalAlignment = Enum.HorizontalAlignment.Center
	contentLayout.VerticalAlignment = Enum.VerticalAlignment.Top
	contentLayout.Padding = UDim.new(0, 12)
	contentLayout.SortOrder = Enum.SortOrder.LayoutOrder
	contentLayout.Parent = contentContainer

	
	Utils.MakeDraggable(outerFrame, titleBar)

	
	local windowState = {
		ScreenGui = screenGui,
		OuterFrame = outerFrame,
		InnerFrame = innerFrame,
		TitleBar = titleBar,
		TitleText = titleText,
		ContentContainer = contentContainer,
		ContentLayout = contentLayout,
		SearchFrame = searchFrame,
		SearchInput = searchInput,
		GlassOverlay = glassOverlay,
		GlowBlob = glowBlob,
		Width = width,
		Height = height,
		MinWidth = minWidth,
		MinHeight = minHeight,
		IsOpen = true,
		Config = config,
	}

	
	function windowState:AddTab(tabName: string, icon: string?)
		local tabData = {
			Name = tabName,
			Icon = icon,
			Content = Instance.new("Frame"),
			IsActive = false,
		}

		tabData.Content.Name = ("Tab_" .. tostring(tabName))
		tabData.Content.Size = UDim2.new(1, 0, 0, 0)
		tabData.Content.Position = UDim2.new(0, 0, 0, 0)
		tabData.Content.BackgroundTransparency = 1
		tabData.Content.Visible = false
		tabData.Content.ZIndex = 2

		local tabLayout = Instance.new("UIListLayout")
		tabLayout.FillDirection = Enum.FillDirection.Vertical
		tabLayout.HorizontalAlignment = Enum.HorizontalAlignment.Center
		tabLayout.VerticalAlignment = Enum.VerticalAlignment.Top
		tabLayout.Padding = UDim.new(0, 12)
		tabLayout.SortOrder = Enum.SortOrder.LayoutOrder
		tabLayout.Parent = tabData.Content

		tabData.Content.Parent = contentContainer

		return tabData
	end

	function windowState:SwitchTab(tabName: string)
		
		for _, child in ipairs(contentContainer:GetChildren()) do
			if child.Name:match("^Tab_") then
				child.Visible = false
			end
		end

		
		local targetTab = contentContainer:FindFirstChild(("Tab_" .. tostring(tabName)))
		if targetTab then
			targetTab.Visible = true

			
			
			
			for i, child in ipairs(targetTab:GetChildren()) do
				if child:IsA("GuiObject") then
					local basePos = child.Position
					child.Position = UDim2.new(basePos.X.Scale, basePos.X.Offset, basePos.Y.Scale, basePos.Y.Offset + 10)

					task.delay(i * 0.03, function()
						Utils.Tween(child, {
							Position = basePos,
						}, 0.3, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)
					end)
				end
			end
		end
	end

	function windowState:Destroy()
		
		Utils.Tween(outerFrame, {
			Size = UDim2.new(0, 0, 0, 0),
			Position = UDim2.new(0.5, 0, 0.5, 0),
		}, 0.3, Enum.EasingStyle.Quart, Enum.EasingDirection.In)

		task.delay(0.3, function()
			outerFrame:Destroy()
			if screenGui then
				screenGui:Destroy()
			end
			Window.Registry[windowState] = nil
			if Window.ActiveWindow == windowState then
				Window.ActiveWindow = nil
			end
		end)
	end

	function windowState:SetTitle(newTitle: string)
		windowState.TitleText.Text = newTitle
	end

	function windowState:Notify(message: string, type: string?)
		local Notification = custom_require("core/notification")
		Notification.Create(message, type or "Info", windowState)
	end

	
	Window.Registry[windowState] = windowState
	Window.ActiveWindow = windowState

	
	outerFrame.Parent = parent

	
	outerFrame.Size = UDim2.new(0, 0, 0, 0)
	outerFrame.Position = UDim2.new(0.5, 0, 0.5, 0)

	Utils.Tween(outerFrame, {
		Size = UDim2.new(0, width, 0, height),
		Position = UDim2.new(0.5, -width / 2, 0.5, -height / 2),
	}, 0.4, Enum.EasingStyle.Quart, Enum.EasingDirection.Out)

	return windowState
end


function Window.DestroyAll()
	for windowState, _ in pairs(Window.Registry) do
		windowState:Destroy()
	end
	table.clear(Window.Registry)
	Window.ActiveWindow = nil
end

return Window
end

-- Init Module



local QwenUI = {}
QwenUI.__index = QwenUI


local Players = game:GetService("Players")


local Theme = custom_require("core/theme")
local Utils = custom_require("core/utils")
local Icons = custom_require("core/icons")
local Window = custom_require("core/window")
local Notification = custom_require("core/notification")


local Section = custom_require("components/layout/section")
local Row = custom_require("components/layout/row")
local Divider = custom_require("components/layout/divider")
local Banner = custom_require("components/layout/banner")

local Button = custom_require("components/inputs/button")
local Toggle = custom_require("components/inputs/toggle")
local Slider = custom_require("components/inputs/slider")
local TextBox = custom_require("components/inputs/textbox")
local Dropdown = custom_require("components/inputs/dropdown")
local MultiDropdown = custom_require("components/inputs/multidropdown")
local ColorPicker = custom_require("components/inputs/colorpicker")
local Keybind = custom_require("components/inputs/keybind")

local Console = custom_require("components/display/console")
local ProgressBar = custom_require("components/display/progressbar")
local Label = custom_require("components/display/label")
local Paragraph = custom_require("components/display/paragraph")
local Image = custom_require("components/display/image")


QwenUI.Version = "1.0.0"
QwenUI.Name = "QwenUILib"


function QwenUI:CreateWindow(config: table)
	config = config or {}
	return Window.Create(config)
end


function QwenUI:AddTab(window, tabName: string, icon: string?)
	if typeof(window) == "Instance" then
		window = window:GetAttribute("QwenWindowState") or window
	end
	return window:AddTab(tabName, icon)
end

function QwenUI:SwitchTab(window, tabName: string)
	if typeof(window) == "Instance" then
		window = window:GetAttribute("QwenWindowState") or window
	end
	window:SwitchTab(tabName)
end


function QwenUI:Notify(message: string, type: string?, parent: Instance?)
	return Notification.Create(message, type, parent)
end


function QwenUI:GetTheme()
	return Theme
end

function QwenUI:ApplyPreset(presetName: string)
	Theme:ApplyPreset(presetName)
	Icons:LoadPreset(presetName)
end


function QwenUI:GetIcons()
	return Icons
end

function QwenUI:RegisterIcon(name: string, assetId: string, weight: string?)
	return Icons:Register(name, assetId, weight)
end


function QwenUI:GetUtils()
	return Utils
end


QwenUI.Section = Section
QwenUI.Row = Row
QwenUI.Divider = Divider
QwenUI.Banner = Banner

QwenUI.Button = Button
QwenUI.Toggle = Toggle
QwenUI.Slider = Slider
QwenUI.TextBox = TextBox
QwenUI.Dropdown = Dropdown
QwenUI.MultiDropdown = MultiDropdown
QwenUI.ColorPicker = ColorPicker
QwenUI.Keybind = Keybind

QwenUI.Console = Console
QwenUI.ProgressBar = ProgressBar
QwenUI.Label = Label
QwenUI.Paragraph = Paragraph
QwenUI.Image = Image


QwenUI.Presets = {
	Default = {
		Theme = Theme,
		Icons = "Phosphor",
	},
	Light = {
		Theme = Theme,
		Icons = "Phosphor",
		Colors = Theme.Light,
	},
}


function QwenUI:UsePreset(presetName: string)
	if self.Presets[presetName] then
		local preset = self.Presets[presetName]
		self:ApplyPreset(preset.Icons)
		
	end
end


function QwenUI:DestroyAll()
	Window.DestroyAll()
end


function QwenUI:Init()
	
	Icons:LoadPreset("Phosphor")

	
	print((tostring(self.Name) .. " v" .. tostring(self.Version) .. " initialized successfully!"))
	print("Premium Roblox UI Library - Awwwards-tier Design System")
	print("Components: Window, Notifications, Section, Row, Divider, Banner")
	print("Inputs: Button, Toggle, Slider, TextBox, Dropdown, MultiDropdown, ColorPicker, Keybind")
	print("Display: Console, ProgressBar, Label, Paragraph, Image")

	return self
end


return QwenUI
